from flask import Flask, request
from flask import jsonify
app = Flask(__name__)
@app.route('/users/<int:id>', methods=['GET'])
def get_user(id):
  if not 1 <= id <= 100:
    return jsonify({'message': 'Invalid ID'}), 400
  # Successful response
  return jsonify({'message': 'Success message'})
